import React from 'react';

function GameIFrame ({ title, embed, page, h, w }) {
  return (
    <div>
      <iframe
        frameborder="0"
        src={embed}
        title={title}
        width={h}
        height={w}
        allowfullscreen="" 
      ></iframe>
      <hr/>
      <a href={page}>Play {title} on itch.io</a>
    </div>
    
  );
};

export default GameIFrame;
